'use client';
import { useAsidemenu } from '@/hooks/useAsideMenu';

export default function Asidemenu() {
  const { isOpen } = useAsidemenu();

  return (
    <>
      {isOpen && (
        <>
          <div className="min-h-screen fixed w-full bg-black/80 z-10"></div>
          <aside className="z-50 fixed right-0 flex h-screen w-[70%] flex-col">
            
          </aside>
        </>
      )}
    </>
  );
}
